mapper.update:
UPDATE user_role
SET role_id = (SELECT id FROM role WHERE name = #{role})
WHERE user_id = #{id}

mapper.select:
SELECT COUNT(*) > 0
FROM user_role ur
         INNER JOIN role_permission rp ON ur.role_id = rp.role_id
         INNER JOIN permission p ON rp.permission_id = p.id
WHERE ur.user_id = #{userId}
  AND p.code = #{permissionCode}
